const DB = 'MangaVizCache', VER = 1, STORE = 'cache';
function open(): Promise<IDBDatabase> { return new Promise((res,rej) => { const r = indexedDB.open(DB,VER); r.onupgradeneeded = () => { if (!r.result.objectStoreNames.contains(STORE)) r.result.createObjectStore(STORE, {keyPath:'k'}); }; r.onsuccess = () => res(r.result); r.onerror = () => rej(r.error); }); }
export async function cacheGet<T>(key: string, ttl = 3600000): Promise<T|null> { try { const db = await open(); return new Promise(r => { const req = db.transaction(STORE,'readonly').objectStore(STORE).get(key); req.onsuccess = () => { const e = req.result; if (!e || Date.now()-e.ts > e.ttl) { if (e) db.transaction(STORE,'readwrite').objectStore(STORE).delete(key); r(null); } else r(e.data as T); }; req.onerror = () => r(null); }); } catch { return null; } }
export async function cacheSet(key: string, data: unknown, ttl = 3600000): Promise<void> { try { const db = await open(); await new Promise<void>((res,rej) => { const t = db.transaction(STORE,'readwrite'); t.objectStore(STORE).put({k:key,data,ts:Date.now(),ttl}); t.oncomplete = () => res(); t.onerror = () => rej(t.error); }); } catch {} }
